40: /**
41:  * This class manages the fetching process with the brokers.
42:  * <p>
43:  * Thread-safety:
44:  * Requests and responses of Fetcher may be processed by different threads since heartbeat
45:  * thread may process responses. Other operations are single-threaded and invoked only from
46:  * the thread polling the consumer.
47:  * <ul>
48:  *     <li>If a response handler accesses any shared state of the Fetcher (e.g. FetchSessionHandler),
49:  *     all access to that state must be synchronized on the Fetcher instance.</li>
50:  *     <li>If a response handler accesses any shared state of the coordinator (e.g. SubscriptionState),
51:  *     it is assumed that all access to that state is synchronized on the coordinator instance by
52:  *     the caller.</li>
53:  *     <li>At most one request is pending for each node at any time. Nodes with pending requests are
54:  *     tracked and updated after processing the response. This ensures that any state (e.g. epoch)
55:  *     updated while processing responses on one thread are visible while creating the subsequent request
56:  *     on a different thread.</li>
57:  * </ul>
58:  */
59: public class Fetcher<K, V> extends AbstractFetch {
60: 
61:     private final Logger log;
62:     private final ConsumerNetworkClient client;
63:     private final FetchCollector<K, V> fetchCollector;
64: 
65:     public Fetcher(LogContext logContext,
66:                    ConsumerNetworkClient client,
67:                    ConsumerMetadata metadata,
68:                    SubscriptionState subscriptions,
69:                    FetchConfig fetchConfig,
70:                    Deserializers<K, V> deserializers,
71:                    FetchMetricsManager metricsManager,
72:                    Time time,
73:                    ApiVersions apiVersions) {
74:         super(logContext, metadata, subscriptions, fetchConfig, new FetchBuffer(logContext), metricsManager, time, apiVersions);
75:         this.log = logContext.logger(Fetcher.class);
76:         this.client = client;
77:         this.fetchCollector = new FetchCollector<>(logContext,
78:                 metadata,
79:                 subscriptions,
80:                 fetchConfig,
81:                 deserializers,
82:                 metricsManager,
83:                 time);
84:     }
85: 
86:     @Override
87:     protected boolean isUnavailable(Node node) {
88:         return client.isUnavailable(node);
89:     }
90: 
91:     @Override
92:     protected void maybeThrowAuthFailure(Node node) {
93:         client.maybeThrowAuthFailure(node);
94:     }
95: 
96:     public void clearBufferedDataForUnassignedPartitions(Collection<TopicPartition> assignedPartitions) {
97:         fetchBuffer.retainAll(new HashSet<>(assignedPartitions));
98:     }
99: 
100:     /**
101:      * Set up a fetch request for any node that we have assigned partitions for which doesn't already have
102:      * an in-flight fetch or pending fetch data.
103:      * @return number of fetches sent
104:      */
105:     public synchronized int sendFetches() {
106:         final Map<Node, FetchSessionHandler.FetchRequestData> fetchRequests = prepareFetchRequests();
107:         sendFetchesInternal(
108:                 fetchRequests,
109:                 (fetchTarget, data, clientResponse) -> {
110:                     synchronized (Fetcher.this) {
111:                         handleFetchSuccess(fetchTarget, data, clientResponse);
112:                     }
113:                 },
114:                 (fetchTarget, data, error) -> {
115:                     synchronized (Fetcher.this) {
116:                         handleFetchFailure(fetchTarget, data, error);
117:                     }
118:                 });
119:         return fetchRequests.size();
120:     }
121: 
122:     protected void maybeCloseFetchSessions(final Timer timer) {
123:         final List<RequestFuture<ClientResponse>> requestFutures = sendFetchesInternal(
124:                 prepareCloseFetchSessionRequests(),
125:                 this::handleCloseFetchSessionSuccess,
126:                 this::handleCloseFetchSessionFailure
127:         );
128: 
129:         // Poll to ensure that request has been written to the socket. Wait until either the timer has expired or until
130:         // all requests have received a response.
131:         while (timer.notExpired() && !requestFutures.stream().allMatch(RequestFuture::isDone)) {
132:             client.poll(timer, null, true);
133:             timer.update();
134:         }
135: 
136:         if (!requestFutures.stream().allMatch(RequestFuture::isDone)) {
137:             // we ran out of time before completing all futures. It is ok since we don't want to block the shutdown
138:             // here.
139:             log.debug("All requests couldn't be sent in the specific timeout period {}ms. " +
140:                     "This may result in unnecessary fetch sessions at the broker. Consider increasing the timeout passed for " +
141:                     "KafkaConsumer.close(...)", timer.timeoutMs());
142:         }
143:     }
144: 
145:     public Fetch<K, V> collectFetch() {
146:         return fetchCollector.collectFetch(fetchBuffer);
147:     }
