195:             responseFuture.addListener(new RequestFutureListener<>() {
196:                 @Override
197:                 public void onSuccess(ClientResponse resp) {
198:                     successHandler.handle(fetchTarget, data, resp);
199:                 }
200: 
201:                 @Override
202:                 public void onFailure(RuntimeException e) {
203:                     errorHandler.handle(fetchTarget, data, e);
204:                 }
205:             });
