408:     /**
409:      * Create fetch requests for all nodes for which we have assigned partitions
410:      * that have no existing requests in flight.
411:      */
412:     protected Map<Node, FetchSessionHandler.FetchRequestData> prepareFetchRequests() {
413:         // Update metrics in case there was an assignment change
414:         metricsManager.maybeUpdateAssignment(subscriptions);
415: 
416:         Map<Node, FetchSessionHandler.Builder> fetchable = new HashMap<>();
417:         long currentTimeMs = time.milliseconds();
418:         Map<String, Uuid> topicIds = metadata.topicIds();
419: 
420:         // This is the set of partitions that have buffered data
421:         Set<TopicPartition> buffered = Collections.unmodifiableSet(fetchBuffer.bufferedPartitions());
422: 
423:         // This is the set of partitions that do not have buffered data
424:         Set<TopicPartition> unbuffered = fetchablePartitions(buffered);
425: 
426:         if (unbuffered.isEmpty()) {
427:             // If there are no partitions that don't already have data locally buffered, there's no need to issue
428:             // any fetch requests at the present time.
429:             return Collections.emptyMap();
430:         }
431: 
432:         Set<Integer> bufferedNodes = bufferedNodes(buffered, currentTimeMs);
433: 
434:         for (TopicPartition partition : unbuffered) {
435:             SubscriptionState.FetchPosition position = positionForPartition(partition);
436:             Optional<Node> nodeOpt = maybeNodeForPosition(partition, position, currentTimeMs);
437: 
438:             if (nodeOpt.isEmpty())
439:                 continue;
440: 
441:             Node node = nodeOpt.get();
442: 
443:             if (isUnavailable(node)) {
444:                 maybeThrowAuthFailure(node);
445: 
446:                 // If we try to send during the reconnect backoff window, then the request is just
447:                 // going to be failed anyway before being sent, so skip sending the request for now
448:                 log.trace("Skipping fetch for partition {} because node {} is awaiting reconnect backoff", partition, node);
449:             } else if (nodesWithPendingFetchRequests.contains(node.id())) {
450:                 // If there's already an inflight request for this node, don't issue another request.
451:                 log.trace("Skipping fetch for partition {} because previous request to {} has not been processed", partition, node);
452:             } else if (bufferedNodes.contains(node.id())) {
453:                 // While a node has buffered data, don't fetch other partition data from it. Because the buffered
454:                 // partitions are not included in the fetch request, those partitions will be inadvertently dropped
455:                 // from the broker fetch session cache. In some cases, that could lead to the entire fetch session
456:                 // being evicted.
457:                 log.trace("Skipping fetch for partition {} because its leader node {} hosts buffered partitions", partition, node);
458:             } else {
459:                 // if there is a leader and no in-flight requests, issue a new fetch
460:                 FetchSessionHandler.Builder builder = fetchable.computeIfAbsent(node, k -> {
461:                     FetchSessionHandler fetchSessionHandler = sessionHandlers.computeIfAbsent(node.id(), n -> new FetchSessionHandler(logContext, n));
462:                     return fetchSessionHandler.newBuilder();
463:                 });
464:                 Uuid topicId = topicIds.getOrDefault(partition.topic(), Uuid.ZERO_UUID);
465:                 FetchRequest.PartitionData partitionData = new FetchRequest.PartitionData(topicId,
466:                         position.offset,
467:                         FetchRequest.INVALID_LOG_START_OFFSET,
468:                         fetchConfig.fetchSize,
469:                         position.currentLeader.epoch,
470:                         Optional.empty());
471:                 builder.add(partition, partitionData);
472: 
473:                 log.debug("Added {} fetch request for partition {} at position {} to node {}", fetchConfig.isolationLevel,
474:                         partition, position, node);
475:             }
476:         }
477: 
478:         return convert(fetchable);
479:     }
