190:                     // we ensure that the offset of the next fetch will point to the next batch, which avoids
191:                     // unnecessary re-fetching of the same batch (in the worst case, the consumer could get stuck
192:                     // fetching the same batch repeatedly).
193:                     if (currentBatch != null)
